"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["291289"],{837883(e){e.exports=JSON.parse('{"tag":{"label":"rendering","permalink":"/dst-api-webdocs/docs/tags/rendering","allTagsPath":"/dst-api-webdocs/docs/tags","count":27,"items":[{"id":"game-scripts/widgets/redux/characterbio","title":"Characterbio","description":"Renders the character biography UI panel, including portrait, status badges, inventory, and scrollable descriptive text sections for a selected character.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/characterbio"},{"id":"game-scripts/widgets/redux/chatline","title":"Chatline","description":"Renders individual chat messages with dynamic content such as user names, messages, and special badges for announcements, system messages, or skins.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/chatline"},{"id":"game-scripts/components/colouradder","title":"Colouradder","description":"Manages additive colour blending stacks for an entity and propagates colour updates to child entities and render systems.","permalink":"/dst-api-webdocs/docs/game-scripts/components/colouradder"},{"id":"game-scripts/components/debugger","title":"Debugger","description":"Provides runtime line-drawing debug visualization for entities by rendering debug lines between specified origin and target points.","permalink":"/dst-api-webdocs/docs/game-scripts/components/debugger"},{"id":"game-scripts/components/drawable","title":"Drawable","description":"Manages the visual appearance of an entity by storing and synchronizing image, atlas, and background assets for rendering in the UI or world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/drawable"},{"id":"game-scripts/falloffdefs","title":"Falloffdefs","description":"Registers specific falloff texture definitions for different tile types using the TileManager.","permalink":"/dst-api-webdocs/docs/game-scripts/falloffdefs"},{"id":"game-scripts/cameras/followcamera","title":"Followcamera","description":"Manages third-person camera following for entities with smooth interpolation, zoom, and shake effects.","permalink":"/dst-api-webdocs/docs/game-scripts/cameras/followcamera"},{"id":"game-scripts/map/graphedge","title":"Graphedge","description":"Represents a bidirectional connection between two graph nodes in the world map, managing rendering, locking, and data persistence for map navigation structures.","permalink":"/dst-api-webdocs/docs/game-scripts/map/graphedge"},{"id":"game-scripts/components/groundshadowhandler","title":"Groundshadowhandler","description":"Manages a ground shadow effect that dynamically scales and positions beneath an entity based on its vertical height.","permalink":"/dst-api-webdocs/docs/game-scripts/components/groundshadowhandler"},{"id":"game-scripts/components/healthbar","title":"Healthbar","description":"Renders a visual health bar and percentage label above an entity, updating in response to health changes.","permalink":"/dst-api-webdocs/docs/game-scripts/components/healthbar"},{"id":"game-scripts/widgets/image","title":"Image","description":"Renders a textured image widget within the UI system, supporting multiple texture states, tinting, scaling, and interaction callbacks.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/image"},{"id":"game-scripts/widgets/itemimage","title":"Itemimage","description":"Renders a visual item frame with dynamic skin/icon display, new/unlocked status indicators, and click interaction handling in UI screens.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/itemimage"},{"id":"game-scripts/prefabs/minimap","title":"Minimap","description":"Creates the minimap entity used for rendering the local area map on the HUD.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/minimap"},{"id":"game-scripts/widgets/nineslice","title":"Nineslice","description":"A UI widget that renders a scalable nine-sliced image by arranging nine sub-elements around a central content area.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/nineslice"},{"id":"game-scripts/components/ocean","title":"Ocean","description":"Manages ocean surface wave direction and speed for rendering or simulation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ocean"},{"id":"game-scripts/components/oceancolor","title":"Oceancolor","description":"Manages dynamic color and texture blending for the ocean floor and sky based on time of day phases (day, dusk, night, no_ocean).","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceancolor"},{"id":"game-scripts/components/playervision","title":"Playervision","description":"Manages visual effects and colour cube overrides for player vision modes including ghost, nightmare, night vision, and various equipment-based vision types.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playervision"},{"id":"game-scripts/postprocesseffects","title":"Postprocesseffects","description":"Extends the PostProcessor engine class with post-processing effect management functions for colour cubes, bloom, distortion, lunacy, and moon pulse shaders.","permalink":"/dst-api-webdocs/docs/game-scripts/postprocesseffects"},{"id":"game-scripts/shadeeffects","title":"Shadeeffects","description":"Manages dynamic leaf canopy shading effects using the ShadeRenderer system, including texture, position, rotation, and strength based on ambient light.","permalink":"/dst-api-webdocs/docs/game-scripts/shadeeffects"},{"id":"game-scripts/components/sheltered_replica","title":"Sheltered Replica","description":"Manages the dynamic shadeoverride state for an entity\'s animation based on its sheltered status, with smooth interpolation between exposed and sheltered values.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sheltered_replica"},{"id":"game-scripts/widgets/speechbubble","title":"Speechbubble","description":"Renders a dynamic speech bubble with a face image and text, positioned relative to a target entity\'s screen coordinates.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/speechbubble"},{"id":"game-scripts/widgets/text","title":"Text","description":"Renders and manages displayable text widgets with dynamic sizing, truncation, alignment, and multiline support for UI elements.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/text"},{"id":"game-scripts/widgets/threeslice","title":"ThreeSlice","description":"A UI widget that renders a horizontally or vertically scalable image by splitting it into three segments: a start cap, a repeating filler, and an optional end cap.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/threeslice"},{"id":"game-scripts/widgets/tilebg","title":"Tilebg","description":"Renders a horizontally or vertically tiled background with optional end caps and separators, used for UI panels and containers.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/tilebg"},{"id":"game-scripts/widgets/tilebg_quagmire","title":"Tilebg Quagmire","description":"Creates and manages horizontal separator images for rendering tile backgrounds in the Quagmire biome UI.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/tilebg_quagmire"},{"id":"game-scripts/tiledefs","title":"Tiledefs","description":"Registers all game tile definitions\u2014including land, ocean, impassable, and noise types\u2014with associated visual, audio, and physical properties via the TileManager.","permalink":"/dst-api-webdocs/docs/game-scripts/tiledefs"},{"id":"game-scripts/widgets/video","title":"Video","description":"Renders a video widget on an entity by interfacing with the VideoWidget component and its underlying video playback system.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/video"}],"unlisted":false}}')}}]);